1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const isAliveNext = (isCurrentlyAlive: boolean, liveNeighborCount: number): boolean =>
15	  liveNeighborCount === 3 || (isCurrentlyAlive && liveNeighborCount === 2);
16	
17	export function nextGeneration(cells: Cell[]): Cell[] {
18	  const liveCellKeys = new Set(cells.map(cellKey));
19	
20	  const candidates = new Map<string, Cell>();
21	  for (const cell of cells) {
22	    candidates.set(cellKey(cell), cell);
23	    for (const neighbor of neighborsOf(cell)) {
24	      candidates.set(cellKey(neighbor), neighbor);
25	    }
26	  }
27	
28	  return [...candidates.values()].filter((cell) => {
29	    const liveNeighborCount = neighborsOf(cell).filter((n) => liveCellKeys.has(cellKey(n))).length;
30	    return isAliveNext(liveCellKeys.has(cellKey(cell)), liveNeighborCount);
31	  });
32	}
33

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single isolated live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a 2x2 block stable (each cell has 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("transforms a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect([...result].sort()).toEqual([...horizontal].sort());
24	  });
25	  it("kills a live cell with 4 neighbors (overpopulation)", () => {
26	    // Center cell (1,1) has 4 neighbors: (0,0), (2,0), (0,2), (2,2)
27	    const input: [number, number][] = [[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]];
28	    const result = nextGeneration(input);
29	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
30	  });
31	  it("brings a dead cell with exactly 3 neighbors to life (reproduction)", () => {
32	    // From spec: [[0,0],[1,0],[0,1]] - dead cell at (1,1) has exactly 3 neighbors
33	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
34	    const result = nextGeneration(input);
35	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(true);
36	  });
37	  it("handles negative coordinates correctly", () => {
38	    // A 2x2 block at negative coordinates should remain stable
39	    const block: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
40	    const result = nextGeneration(block);
41	    expect([...result].sort()).toEqual([...block].sort());
42	  });
43	});
