export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCellKeys = new Set(cells.map(cellKey));

  const candidates = new Map<string, Cell>();
  for (const cell of cells) {
    candidates.set(cellKey(cell), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(cellKey(neighbor), neighbor);
    }
  }

  return [...candidates.values()].filter((cell) => {
    const liveNeighborCount = neighborsOf(cell).filter((n) => liveCellKeys.has(cellKey(n))).length;
    return isAliveNext(liveCellKeys.has(cellKey(cell)), liveNeighborCount);
  });
}

